module bar(clk, rst, inp, out);
  input wire clk;
  input wire rst;
  input wire inp;
  output reg out;
  always @(posedge clk) if (rst) out <= 1'd0; else out <= ~inp;
endmodule

module foo(clk, rst, inp, out);
  input wire clk;
  input wire rst;
  input wire inp;
  output wire out;
  bar bar_instance ( (* clock_connected *) clk, rst, (* this_is_the_input *) inp, out);
endmodule

module foo(clk, rst, inp_a, inp_b, out);
  input wire clk;
  input wire rst;
  input wire [7:0] inp_a;
  input wire [7:0] inp_b;
  output wire [7:0] out;

  function [7:0] do_add;
    input [7:0] inp_a;
    input [7:0] inp_b;
    do_add = inp_a + inp_b;
  endfunction

  always @(posedge clk)
    if (rst) out <= 0;
    else out <= do_add (* combinational_adder *) (inp_a, inp_b);
endmodule
